@Experimental
final class PatternRowCursor implements RowCursor {
	final PatternPlan pattern;
	final RowState row;
	final PatternCursor cursor;
	int activeMark = -1;

	PatternRowCursor(PatternPlan pattern, RowState row, PatternCursor cursor) {
		this.pattern = pattern;
		this.row = row;
		this.cursor = cursor;
	}

	@Override
	public boolean next() throws IOException {
		release();
		long[] quad;
		while ((quad = cursor.next()) != null) {
			int mark = row.mark();
			if (pattern.bind(quad, row)) {
				activeMark = mark;
				return true;
			}
			row.rollback(mark);
		}
		return false;
	}

	@Override
	public void close() {
		release();
		cursor.close();
	}

	void release() {
		if (activeMark >= 0) {
			row.rollback(activeMark);
			activeMark = -1;
		}
	}
}
